import{_ as a,c as s,o as i,a1 as n}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Gestión de habilidades: Consultar habilidades disponibles | opencode-agent-skills","description":"Aprende el uso de la herramienta get_available_skills. Localiza habilidades rápidamente mediante búsqueda, espacios de nombres y filtrado, dominando las funciones principales de descubrimiento y gestión de habilidades.","frontmatter":{"title":"Gestión de habilidades: Consultar habilidades disponibles | opencode-agent-skills","sidebarTitle":"Buscar habilidades rápidamente","subtitle":"Gestión de habilidades: Consultar habilidades disponibles","description":"Aprende el uso de la herramienta get_available_skills. Localiza habilidades rápidamente mediante búsqueda, espacios de nombres y filtrado, dominando las funciones principales de descubrimiento y gestión de habilidades.","tags":["gestión de habilidades","uso de herramientas","espacios de nombres"],"prerequisite":["start-installation"],"order":2},"headers":[],"relativePath":"es/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md","filePath":"es/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"}'),l={name:"es/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"};function o(d,e,t,r,c,p){return i(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="consultar-y-listar-habilidades-disponibles" tabindex="-1">Consultar y listar habilidades disponibles <a class="header-anchor" href="#consultar-y-listar-habilidades-disponibles" aria-label="Permalink to &quot;Consultar y listar habilidades disponibles&quot;">​</a></h1><h2 id="lo-que-podras-hacer-despues-de-completar-esta-leccion" tabindex="-1">Lo que podrás hacer después de completar esta lección <a class="header-anchor" href="#lo-que-podras-hacer-despues-de-completar-esta-leccion" aria-label="Permalink to &quot;Lo que podrás hacer después de completar esta lección&quot;">​</a></h2><ul><li>Utilizar la herramienta <code>get_available_skills</code> para listar todas las habilidades disponibles</li><li>Filtrar habilidades específicas mediante consultas de búsqueda</li><li>Usar espacios de nombres (como <code>project:skill-name</code>) para localizar habilidades con precisión</li><li>Identificar el origen de habilidades y la lista de scripts ejecutables</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p>Deseas usar una habilidad, pero no recuerdas su nombre exacto. Quizás sabes que es una habilidad del proyecto, pero no sabes en qué ruta de descubrimiento se encuentra. O simplemente quieres explorar rápidamente qué habilidades tiene disponible el proyecto actual.</p><h2 id="cuando-usar-esta-tecnica" tabindex="-1">Cuándo usar esta técnica <a class="header-anchor" href="#cuando-usar-esta-tecnica" aria-label="Permalink to &quot;Cuándo usar esta técnica&quot;">​</a></h2><ul><li><strong>Explorar nuevos proyectos</strong>: Al unirte a un nuevo proyecto, conocer rápidamente qué habilidades están disponibles</li><li><strong>Nombre de habilidad incierto</strong>: Solo recuerdas parte del nombre o descripción de la habilidad, necesitando coincidencia aproximada</li><li><strong>Conflictos de múltiples espacios de nombres</strong>: Existen habilidades con el mismo nombre a nivel de proyecto y de usuario, necesitas especificar explícitamente cuál usar</li><li><strong>Buscar scripts</strong>: Quieres saber qué scripts de automatización hay disponibles en el directorio de habilidades</li></ul><h2 id="idea-central" tabindex="-1">Idea central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea central&quot;">​</a></h2><p>La herramienta <code>get_available_skills</code> te ayuda a ver todas las habilidades disponibles en la sesión actual. El complemento escanea automáticamente habilidades desde 6 rutas de descubrimiento:</p><div class="info custom-block"><p class="custom-block-title">Prioridad de descubrimiento de habilidades</p><ol><li><code>.opencode/skills/</code> (OpenCode a nivel de proyecto)</li><li><code>.claude/skills/</code> (Claude a nivel de proyecto)</li><li><code>~/.config/opencode/skills/</code> (OpenCode a nivel de usuario)</li><li><code>~/.claude/skills/</code> (Claude a nivel de usuario)</li><li><code>~/.claude/plugins/cache/</code> (caché de complementos)</li><li><code>~/.claude/plugins/marketplaces/</code> (complementos instalados)</li></ol></div><p>Las habilidades con el mismo nombre solo conservan la primera según la prioridad, las posteriores son ignoradas.</p><p>La información devuelta por la herramienta incluye:</p><ul><li><strong>Nombre de habilidad</strong></li><li><strong>Etiqueta de origen</strong> (project, user, claude-project, etc.)</li><li><strong>Descripción</strong></li><li><strong>Lista de scripts ejecutables</strong> (si los hay)</li></ul><div class="tip custom-block"><p class="custom-block-title">Sintaxis de espacios de nombres</p><p>Puedes especificar explícitamente el origen usando el formato <code>namespace:skill-name</code>:</p><ul><li><code>project:my-skill</code> - Usar habilidad de OpenCode a nivel de proyecto (<code>.opencode/skills/</code>)</li><li><code>claude-project:my-skill</code> - Usar habilidad de Claude a nivel de proyecto (<code>.claude/skills/</code>)</li><li><code>user:my-skill</code> - Usar habilidad de OpenCode a nivel de usuario (<code>~/.config/opencode/skills/</code>)</li><li><code>claude-user:my-skill</code> - Usar habilidad de Claude a nivel de usuario (<code>~/.claude/skills/</code>)</li><li><code>claude-plugins:my-skill</code> - Usar habilidad de complementos de Claude</li></ul></div><h2 id="sigueme" tabindex="-1">Sígueme <a class="header-anchor" href="#sigueme" aria-label="Permalink to &quot;Sígueme&quot;">​</a></h2><h3 id="paso-1-listar-todas-las-habilidades-disponibles" tabindex="-1">Paso 1: Listar todas las habilidades disponibles <a class="header-anchor" href="#paso-1-listar-todas-las-habilidades-disponibles" aria-label="Permalink to &quot;Paso 1: Listar todas las habilidades disponibles&quot;">​</a></h3><p>En OpenCode, pide directamente a la IA que liste las habilidades:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrada del usuario:</span></span>
<span class="line"><span>Listar todas las habilidades disponibles</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Respuesta del sistema:</span></span>
<span class="line"><span>skill-helper (project)</span></span>
<span class="line"><span>  Asistente de operaciones Git y gestión de ramas [scripts: tools/branch.sh, tools/commit.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  Herramienta de pruebas unitarias y análisis de cobertura</span></span>
<span class="line"><span></span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Guía de contenedorización y despliegue con Docker [scripts: build.sh, deploy.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>claude-code-superpowers (claude-plugins)</span></span>
<span class="line"><span>  Flujo de trabajo completo de desarrollo de software</span></span></code></pre></div><p><strong>Lo que deberías ver</strong>: Una lista de habilidades, mostrando para cada una el nombre, etiqueta de origen, descripción y lista de scripts.</p><h3 id="paso-2-usar-consultas-de-busqueda-para-filtrar" tabindex="-1">Paso 2: Usar consultas de búsqueda para filtrar <a class="header-anchor" href="#paso-2-usar-consultas-de-busqueda-para-filtrar" aria-label="Permalink to &quot;Paso 2: Usar consultas de búsqueda para filtrar&quot;">​</a></h3><p>Si solo recuerdas parte del nombre de la habilidad:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrada del usuario:</span></span>
<span class="line"><span>Buscar habilidades que contengan &quot;docker&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Respuesta del sistema:</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Guía de contenedorización y despliegue con Docker [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>La búsqueda coincide con palabras clave en el nombre y descripción de la habilidad, soporta el comodín <code>*</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrada del usuario:</span></span>
<span class="line"><span>Buscar habilidades que comiencen con &quot;test&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Respuesta del sistema:</span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  Herramienta de pruebas unitarias y análisis de cobertura</span></span></code></pre></div><p><strong>Lo que deberías ver</strong>: Solo se muestran las habilidades que coinciden con la consulta.</p><h3 id="paso-3-experimentar-con-sugerencias-de-coincidencia-aproximada" tabindex="-1">Paso 3: Experimentar con sugerencias de coincidencia aproximada <a class="header-anchor" href="#paso-3-experimentar-con-sugerencias-de-coincidencia-aproximada" aria-label="Permalink to &quot;Paso 3: Experimentar con sugerencias de coincidencia aproximada&quot;">​</a></h3><p>Si ingresas un nombre de habilidad incorrecto:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrada del usuario:</span></span>
<span class="line"><span>Quiero usar docker-asistant</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Respuesta del sistema:</span></span>
<span class="line"><span>No se encontraron habilidades que coincidan con &quot;docker-asistant&quot;. ¿Quisiste decir &quot;docker-helper&quot;?</span></span></code></pre></div><p>El complemento calcula la similitud basándose en la distancia de Levenshtein y sugiere automáticamente el nombre de habilidad más cercano.</p><p><strong>Lo que deberías ver</strong>: Mensaje de error y sugerencia de la habilidad correcta.</p><h3 id="paso-4-usar-espacios-de-nombres-para-localizar-con-precision" tabindex="-1">Paso 4: Usar espacios de nombres para localizar con precisión <a class="header-anchor" href="#paso-4-usar-espacios-de-nombres-para-localizar-con-precision" aria-label="Permalink to &quot;Paso 4: Usar espacios de nombres para localizar con precisión&quot;">​</a></h3><p>Supongamos que tanto a nivel de proyecto como de usuario existe una habilidad llamada <code>build-helper</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrada del usuario:</span></span>
<span class="line"><span>Listar información detallada de build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Respuesta del sistema:</span></span>
<span class="line"><span>build-helper (project)</span></span>
<span class="line"><span>  Configuración de construcción específica del proyecto y optimización de compilación [scripts: build.sh, optimize.sh]</span></span></code></pre></div><p>Si el usuario quiere la habilidad a nivel de usuario:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrada del usuario:</span></span>
<span class="line"><span>Usar user:build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Respuesta del sistema:</span></span>
<span class="line"><span>build-helper (user)</span></span>
<span class="line"><span>  Cadena de herramientas de construcción general y configuración de integración continua [scripts: ci.sh, test.sh]</span></span></code></pre></div><p><strong>Lo que deberías ver</strong>: Mediante el prefijo de espacio de nombres puedes acceder a habilidades con el mismo nombre de diferentes orígenes.</p><h3 id="paso-5-verificar-scripts-ejecutables" tabindex="-1">Paso 5: Verificar scripts ejecutables <a class="header-anchor" href="#paso-5-verificar-scripts-ejecutables" aria-label="Permalink to &quot;Paso 5: Verificar scripts ejecutables&quot;">​</a></h3><p>Ver qué scripts hay en el directorio de habilidades:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrada del usuario:</span></span>
<span class="line"><span>¿Qué scripts tiene docker-helper?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Respuesta del sistema:</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Guía de contenedorización y despliegue con Docker [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>Los scripts se muestran entre corchetes en la información de habilidad, separados por comas. Puedes ejecutar estos scripts usando la herramienta <code>run_skill_script</code>.</p><p><strong>Lo que deberías ver</strong>: Después del nombre de habilidad aparece una lista en formato <code>[scripts: ruta-de-script1, ruta-de-script2, ...]</code>.</p><h2 id="punto-de-control-✅" tabindex="-1">Punto de control ✅ <a class="header-anchor" href="#punto-de-control-✅" aria-label="Permalink to &quot;Punto de control ✅&quot;">​</a></h2><ul><li>[ ] ¿Puedes listar todas las habilidades disponibles?</li><li>[ ] ¿Puedes filtrar habilidades específicas mediante consultas de búsqueda?</li><li>[ ] ¿Puedes comprender el significado de las etiquetas de origen de habilidades (project, user, claude-project, etc.)?</li><li>[ ] ¿Puedes explicar la función y la sintaxis de los espacios de nombres de habilidades?</li><li>[ ] ¿Puedes identificar la lista de scripts ejecutables desde la información de habilidad?</li></ul><h2 id="advertencias-sobre-trampas" tabindex="-1">Advertencias sobre trampas <a class="header-anchor" href="#advertencias-sobre-trampas" aria-label="Permalink to &quot;Advertencias sobre trampas&quot;">​</a></h2><h3 id="trampa-1-sobrescritura-de-habilidades-con-el-mismo-nombre" tabindex="-1">Trampa 1: Sobrescritura de habilidades con el mismo nombre <a class="header-anchor" href="#trampa-1-sobrescritura-de-habilidades-con-el-mismo-nombre" aria-label="Permalink to &quot;Trampa 1: Sobrescritura de habilidades con el mismo nombre&quot;">​</a></h3><p>Si a nivel de proyecto y de usuario existen habilidades con el mismo nombre, podrías confundirte sobre por qué no se carga la habilidad que esperabas.</p><p><strong>Causa</strong>: Las habilidades se descubren por prioridad, el nivel de proyecto tiene prioridad sobre el nivel de usuario, con el mismo nombre solo se conserva la primera.</p><p><strong>Solución</strong>: Especifica explícitamente usando espacios de nombres, como <code>user:my-skill</code> en lugar de <code>my-skill</code>.</p><h3 id="trampa-2-busqueda-sensible-a-mayusculas-y-minusculas" tabindex="-1">Trampa 2: Búsqueda sensible a mayúsculas y minúsculas <a class="header-anchor" href="#trampa-2-busqueda-sensible-a-mayusculas-y-minusculas" aria-label="Permalink to &quot;Trampa 2: Búsqueda sensible a mayúsculas y minúsculas&quot;">​</a></h3><p>Las consultas de búsqueda usan expresiones regulares, pero están configuradas con el flag <code>i</code>, por lo que no distinguen mayúsculas y minúsculas.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Estas búsquedas son equivalentes</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;DOCKER&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;Docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="trampa-3-escapar-comodines" tabindex="-1">Trampa 3: Escapar comodines <a class="header-anchor" href="#trampa-3-escapar-comodines" aria-label="Permalink to &quot;Trampa 3: Escapar comodines&quot;">​</a></h3><p>El <code>*</code> en la búsqueda se convierte automáticamente a la expresión regular <code>.*</code>, no necesitas escaparlo manualmente:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Buscar habilidades que comiencen con &quot;test&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;test*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Equivalente a la expresión regular /test.*/i</span></span></code></pre></div><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de esta lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de esta lección&quot;">​</a></h2><p><code>get_available_skills</code> es una herramienta para explorar el ecosistema de habilidades, soporta:</p><ul><li><strong>Listar todas las habilidades</strong>: Llamar sin parámetros</li><li><strong>Filtrado de búsqueda</strong>: Coincidir nombres y descripciones mediante el parámetro <code>query</code></li><li><strong>Espacios de nombres</strong>: Localizar con precisión usando <code>namespace:skill-name</code></li><li><strong>Sugerencias de coincidencia aproximada</strong>: Sugerir automáticamente el nombre correcto al cometer errores de escritura</li><li><strong>Lista de scripts</strong>: Mostrar scripts de automatización ejecutables</li></ul><p>El complemento inyecta automáticamente la lista de habilidades al inicio de la sesión, por lo que generalmente no necesitas llamar manualmente a esta herramienta. Pero es útil en los siguientes escenarios:</p><ul><li>Quieres explorar rápidamente las habilidades disponibles</li><li>No recuerdas el nombre exacto de la habilidad</li><li>Necesitas distinguir diferentes orígenes de habilidades con el mismo nombre</li><li>Quieres ver la lista de scripts de una habilidad específica</li></ul><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos <strong><a href="./../loading-skills-into-context/">Cargar habilidades en el contexto de la sesión</a></strong>.</p><p>Aprenderás:</p><ul><li>Usar la herramienta use_skill para cargar habilidades a la sesión actual</li><li>Comprender cómo el contenido de las habilidades se inyecta en el contexto en formato XML</li><li>Dominar el mecanismo de Synthetic Message Injection (inyección de mensajes sintéticos)</li><li>Entender cómo las habilidades permanecen disponibles después de la compresión de la sesión</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fuente" tabindex="-1">Apéndice: Referencia de código fuente <a class="header-anchor" href="#apendice-referencia-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia de código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver la ubicación del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidad</th><th>Ruta del archivo</th><th>Línea</th></tr></thead><tbody><tr><td>Definición de la herramienta GetAvailableSkills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L29-L72" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>29-72</td></tr><tr><td>Función discoverAllSkills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L240-L263" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>240-263</td></tr><tr><td>Función resolveSkill</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L269-L283" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>269-283</td></tr><tr><td>Función findClosestMatch</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L88-L125" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>88-125</td></tr></tbody></table><p><strong>Tipos clave</strong>:</p><ul><li><code>SkillLabel = &quot;project&quot; | &quot;user&quot; | &quot;claude-project&quot; | &quot;claude-user&quot; | &quot;claude-plugins&quot;</code>: Enumeración de etiquetas de origen de habilidades</li></ul><p><strong>Constantes clave</strong>:</p><ul><li>Umbral de coincidencia aproximada: <code>0.4</code> (<code>utils.ts:124</code>) - Similaridad inferior a este valor no devuelve sugerencias</li></ul><p><strong>Funciones clave</strong>:</p><ul><li><code>GetAvailableSkills()</code>: Devuelve la lista de habilidades formateada, soporta filtrado por consulta y sugerencias de coincidencia aproximada</li><li><code>resolveSkill(skillName: string, skillsByName: Map&lt;string, Skill&gt;)</code>: Soporta análisis de habilidades en formato <code>namespace:skill-name</code></li><li><code>findClosestMatch(input: string, candidates: string[])</code>: Calcula la mejor coincidencia basándose en múltiples estrategias de coincidencia (prefijo, contiene, distancia de edición)</li></ul><p><strong>Reglas de negocio</strong>:</p><ul><li>Las habilidades con el mismo nombre se deduplican según el orden de descubrimiento, solo se conserva la primera (<code>skills.ts:258</code>)</li><li>Las consultas de búsqueda soportan el comodín <code>*</code>, convertido automáticamente a expresión regular (<code>tools.ts:43</code>)</li><li>Las sugerencias de coincidencia aproximada solo se activan cuando hay un parámetro de consulta y no hay resultados (<code>tools.ts:49-57</code>)</li></ul></details>`,64)])])}const b=a(l,[["render",o]]);export{h as __pageData,b as default};
